/* adm-menu-userscreen-sql-oracle.xml - insertUserScreen */
INSERT INTO TADMIN_MST_URSCR (
	  APKEY
	, USKEY
	, USNM
	, USPATH
	, USSCHDKEY
	, ISDWUS
	, NXPATH
	, URINFOYN
	, CMT
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
) VALUES (
	  #{apkey}
	, #{uskey}
	, #{usnm}
	, #{uspath}
	, #{usschdkey}
	, #{isdwus}
	, #{nxpath}
	, #{urinfoyn}
	, #{cmt}
	, #{sysdate}
	, #{surkey}
	, #{sysdate}
	, #{surkey}
)

mapper.update:
/* adm-menu-userscreen-sql-oracle.xml - updateUserScreen */
UPDATE
    TADMIN_MST_URSCR
SET
      USNM = #{usnm}
	, USPATH = #{uspath}
	, USSCHDKEY = #{usschdkey}
	, ISDWUS = #{isdwus}
	, NXPATH = #{nxpath}
    , URINFOYN = #{urinfoyn}
	, CMT = #{cmt}
  	, UPDATEDATE = #{sysdate}
	, UPDATEURKEY = #{surkey}
WHERE USKEY = #{uskey}
AND APKEY = #{apkey}

